import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';
import { ClickThroughStateParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/ClickThroughStateParser';

export class ClickThroughStateEvent
    extends MessageEvent
    implements IMessageEvent
{
    constructor(callback: Function) {
        super(callback, ClickThroughStateParser);
    }

    public getParser(): ClickThroughStateParser {
        return this.parser as ClickThroughStateParser;
    }
}
